module top_module(
    input [3:0] a,
    input [3:0] b,
    input select,
    input clk,  // Added clk as an input
    output reg [3:0] out
);wire [3:0] xnor_result;
wire [3:0] xnor_out;

assign xnor_result = {a[3]^b[3], a[2]^b[2], a[1]^b[1], a[0]^b[0]};
assign xnor_out = ~xnor_result;

always @(posedge clk) begin
    if (select) begin
        out <= xnor_out;
    end else begin
        out <= xnor_result;
    end
end

endmodule
